  "description": {{ with .Description }}{{ . | jsonify }}{{ else }}{{ .Site.Params.description | jsonify }}{{ end }},
  "url": {{ .Permalink | jsonify }},
  "mainEntityOfPage": {
    "@type": "WebPage",
    "@id": {{ .Permalink | jsonify }}
  },
  "author": {
    "@type": "Organization",
    "name": "Meow Language",
    "url": {{ .Site.BaseURL | jsonify }}
  },
  "publisher": {
    "@type": "Organization",
    "name": "Meow Language",
    "url": {{ .Site.BaseURL | jsonify }},
    "logo": {
      "@type": "ImageObject",
      "url": {{ printf "%sfavicon.svg" .Site.BaseURL | jsonify }}
    }
  },
  "image": {{ printf "%s%s" .Site.BaseURL (default "favicon.svg" .Site.Params.ogpImage) | jsonify }}{{ if not .Date.IsZero }},
  "datePublished": {{ .Date.Format "2006-01-02T15:04:05Z07:00" | jsonify }}{{ end }}{{ if not .Lastmod.IsZero }},
  "dateModified": {{ .Lastmod.Format "2006-01-02T15:04:05Z07:00" | jsonify }}{{ end }}
}
</script>
{{ end }}

