/* ── Footer ── */
.site-footer {
  background: var(--color-bg-hero);
  color: rgba(255, 255, 255, 0.7);
  padding: 3rem 0 2rem;
}

.footer-grid {
  display: grid;
  grid-template-columns: 1.5fr 1fr 1fr 1fr;
  gap: 3rem;
  padding-bottom: 2rem;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.footer-logo {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-weight: 700;
  font-size: 1.1rem;
  color: #fff;
  margin-bottom: 0.75rem;
}

.footer-about p {
  font-size: 0.9rem;
  line-height: 1.6;
}

.footer-links h4 {
  color: #fff;
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 1rem;
}
